const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');
const sharp = require('sharp');
const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));
app.post('/upload', multer().single('file'), async (req, res) => {
  const file = req.file;

  if (!file || !file.originalname)
    return res
      .status(400)
      .json({ message: 'No file uploaded' })
      .end();

  let ext = path.extname(file.originalname).toLowerCase();

  // Check the file extension
  switch (ext) {
    case '.jpg':
    case '.jpeg':
    case '.png':
    case '.gif':
    case '.svg':
      ext = 'image';
      break;

    case '.pdf':
    case '.doc':
    case '.docx':
      ext = 'document';
      break;

    default:
      return res
        .status(400)
        .json({ message: `Invalid file type ${ext}` })
        .end();
  }

  // Create a new filename for the uploaded file.
  const fileName = `${Date.now()}-${file.originalname}`;

  try {
    await fs.promises.access(`public/uploads/${fileName}`);

    return res
      .status(409)
      .json({ message: 'File already exists' })
      .end();
  } catch (err) {}

  // Store the uploaded file in public/uploads directory.
  const filePath = path.join('public', 'uploads', fileName);
  await fs.promises.rename(file.path, filePath);

  if (ext === 'image') {
    try {
      let thumbPath = `public/uploads/${fileName}-thumb`;

      // Create a thumbnail for the uploaded image file.
      const thumb = sharp()
        .resize({ width: 200 })
        .toFile(thumbPath, () => {});

      await fs.promises.access(`public/uploads/${fileName}`);
    } catch (err) {}
  }

  res
    .status(201)
    .json({ message: 'File uploaded successfully' })
    .end();
});
